  tabler="IconCopyright"
  hugeicons="CopyrightIcon"
  phosphor="Copyright"
  remixicon="RiCopyrightLine"
  className="mly:h-4 mly:w-4"
/>,
  command: ({ editor, range }) => {
    const currentYear = new Date().getFullYear();

    editor
      .chain()
      .focus()
      .deleteRange(range)
      .insertContent({
        type: 'paragraph',
        attrs: { textAlign: 'center', showIfKey: null },
        content: [
          {
            type: 'text',
            marks: [{ type: 'textStyle', attrs: { color: '#AAAAAA' } }],
            text: `Maily © ${currentYear}. All rights reserved.`,
          },
        ],
      })
      .run();
  },
};

