        className="mly:flex mly:w-max mly:gap-0.5 mly:rounded-lg mly:p-0.5!"
        side="top"
        sideOffset={8}
        align="center"
        onOpenAutoFocus={(e) => {
          e.preventDefault();
        }}
        onCloseAutoFocus={(e) => {
          e.preventDefault();
        }}
      >
        {Object.entries(alignments).map(([key, value]) => {
          return (
            <BubbleMenuButton
              key={key}
