import { IconPlaceholder } from "@/components/icon-placeholder"
import type { Editor } from '@tiptap/core';
import { BlockItem } from '../../../blocks';

import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from '../../components/ui/tooltip';
import { useCallback, useState, useRef, useEffect, RefObject } from 'react';
import { cn } from '../../utils/classname';

type SlashCommandItemProps = {
  item: BlockItem;
  groupIndex: number;
  commandIndex: number;
  selectedGroupIndex: number;
  selectedCommandIndex: number;
  editor: Editor;
  activeCommandRef: RefObject<HTMLButtonElement> | null;
  selectItem: (groupIndex: number, commandIndex: number) => void;
  hoveredItemKey: string | null;
  onHover: (isHovered: boolean) => void;
};

export function SlashCommandItem(props: SlashCommandItemProps) {
  const {
    item,
    groupIndex,
    commandIndex,
    selectedGroupIndex,
    selectedCommandIndex,
    editor,
    activeCommandRef,
    selectItem,
    hoveredItemKey,
    onHover,
  } = props;

  const [open, setOpen] = useState(false);
  const isActive =
    groupIndex === selectedGroupIndex && commandIndex === selectedCommandIndex;

  const itemKey = `${groupIndex}-${commandIndex}`;
  const isHovered = hoveredItemKey === itemKey;

  const isSubCommand = item && 'commands' in item;

  // show tooltip only if this item is hovered OR (active/keyboard selected AND no other item is hovered)
  const shouldOpenTooltip =
    !!item?.preview && (isHovered || (isActive && !hoveredItemKey));

  const hasRenderFunction = typeof item.render === 'function';
  const renderFunctionValue = hasRenderFunction ? item.render?.(editor) : null;

  let value = (
    <>
      <div className="mly:flex mly:h-6 mly:w-6 mly:shrink-0 mly:items-center mly:justify-center">
        {item.icon}
      </div>
      <div className="mly:grow">
        <p className="mly:font-medium">{item.title}</p>
        <p className="mly:text-xs mly:text-gray-400">{item.description}</p>
      </div>

      {isSubCommand && (
        <span className="mly:block mly:px-1 mly:text-gray-400">
          <IconPlaceholder
  lucide="ChevronRightIcon"
  tabler="IconChevronRight"
  hugeicons="ChevronRightIcon"
  phosphor="CaretRight"
  remixicon="RiArrowRightSLine"
  className="mly:size-3.5 mly:stroke-[2.5]"
/>
        </span>
      )}
    </>
  );

  if (renderFunctionValue !== null && renderFunctionValue !== true) {
    value = renderFunctionValue!;
  }

  const openTimerRef = useRef<number>(0);
  const handleDelayedOpen = useCallback(() => {
    window.clearTimeout(openTimerRef.current);
    const delay = 200;
    openTimerRef.current = window.setTimeout(() => {
      setOpen(true);
      openTimerRef.current = 0;
    }, delay);
  }, [setOpen]);

  useEffect(() => {
    if (shouldOpenTooltip) {
      handleDelayedOpen();
    } else {
      window.clearTimeout(openTimerRef.current);
      openTimerRef.current = 0;
      setOpen(false);
    }
  }, [shouldOpenTooltip]);

  useEffect(() => {
    return () => {
      if (openTimerRef.current) {
        window.clearTimeout(openTimerRef.current);
        openTimerRef.current = 0;
      }
    };
  }, []);

  return (
    <Tooltip open={open} key={`${groupIndex}-${commandIndex}`}>
      <TooltipTrigger asChild>
        <button
          className={cn(
            'mly:flex mly:w-full mly:items-center mly:gap-2 mly:rounded-md mly:px-2 mly:py-1 mly:text-left mly:text-sm mly:text-gray-900 mly:hover:bg-gray-100 mly:hover:text-gray-900',
            isActive
              ? 'mly:bg-gray-100 mly:text-gray-900'
              : 'mly:bg-transparent'
          )}
          onClick={() => selectItem(groupIndex, commandIndex)}
          onMouseEnter={() => onHover(true)}
          onMouseLeave={() => onHover(false)}
          type="button"
          ref={isActive ? activeCommandRef : null}
        >
          {value}
        </button>
      </TooltipTrigger>
      <TooltipContent
        side="right"
        sideOffset={10}
        className="mly:w-52 mly:rounded-lg mly:border-none mly:p-1 mly:shadow"
      >
        {typeof item.preview === 'function' ? (
          item?.preview(editor)
        ) : (
          <>
            <figure className="mly:relative mly:aspect-[2.5] mly:w-full mly:overflow-hidden mly:rounded-md mly:border mly:border-gray-200">
              <img
                src={item?.preview}
                alt={item?.title}
                className="mly:absolute mly:inset-0 mly:h-full mly:w-full mly:object-cover"
              />
            </figure>
            <p className="mly:mt-2 mly:px-0.5 mly:text-gray-500">
              {item.description}
            </p>
          </>
        )}
      </TooltipContent>
    </Tooltip>
  );
}

import { BlockGroupItem, BlockItem } from '../../../blocks';
import { Editor } from '@tiptap/core';

type SlashCommandFilterOptions = {
  readonly groups: BlockGroupItem[];
  query: string;
  editor: Editor;
};

export function filterSlashCommands(options: SlashCommandFilterOptions) {
  const { groups, query, editor } = options;
  const newGroups = [...groups];
  let searchQuery = query?.toLowerCase();

  const subCommandMatch = searchQuery.match(/^([^.]+)\./);

  // so if we are inside a subcommand we need to
  // filter the commands based on the remaining search
  if (subCommandMatch) {
    const [match, subCommandId] = subCommandMatch;
    const subCommandGroup = findSubCommandGroup(groups, subCommandId);

    if (subCommandGroup) {
      // headers.something -> headers. -> something (remainingSearch)
      const remainingSearch = searchQuery.slice(match.length);
      const filteredCommands = subCommandGroup.commands.filter(
        (item) => !remainingSearch || isCommandMatch(item, remainingSearch)
      );

      return filteredCommands.length
        ? [
            {
              ...subCommandGroup,
              commands: filteredCommands,
            },
          ]
        : [];
    }
  }

  const filteredGroups = newGroups
    .map((group) => {
      return {
        ...group,
        commands: group.commands.flatMap((item) =>
          processCommand({ item, search: searchQuery, editor })
        ),
      };
    })
    .filter((group) => group.commands.length > 0);

  return filteredGroups;
}

type SubCommandGroup = BlockItem & {
  id: string;
  commands: BlockItem[];
};

function findSubCommandGroup(
  groups: BlockGroupItem[],
  subCommandId: string
): SubCommandGroup | undefined {
  return groups
    .flatMap((group) => group.commands)
    .find(
      (item) =>
        'commands' in item &&
        item.id?.toLowerCase() === subCommandId.toLowerCase()
    ) as SubCommandGroup | undefined;
}

function containsText(text: string | undefined, search: string): boolean {
  if (!text) {
    return false;
  }

  return text.toLowerCase().includes(search.toLowerCase());
}

function isCommandMatch(item: BlockItem, search: string): boolean {
  return (
    containsText(item.title, search) ||
    containsText(item.description, search) ||
    (item.searchTerms?.some((term) => containsText(term, search)) ?? false)
  );
}

function isSubCommand(item: BlockItem): item is SubCommandGroup {
  return 'commands' in item && Array.isArray(item.commands) && !!item.id;
}

type ProcessCommandOptions = {
  item: BlockItem;
  search: string;
  editor: Editor;
};

function processCommand(options: ProcessCommandOptions): BlockItem[] {
  const { item, search, editor } = options;

  const show = item?.render?.(editor);
  if (show === null) {
    return [];
  }

  const isSearching = search.length > 0;
  if (isSubCommand(item)) {
    // if we are not searching, we want to return a navigable command
    // that will navigate to the group so that we can navigate into it
    // using the arrow keys / enter key
    // @ts-expect-error
    const navigableCommand: BlockItem = {
      ...item,
      command: (options) => {
        const { editor, range } = options;
        editor.chain().focus().insertContentAt(range, `/${item.id}.`).run();
      },
    };

    // first check if the item matches the search
    const matched = isCommandMatch(navigableCommand, search);
    if (matched) {
      return [navigableCommand];
    }

    // so the main command does not match the search
    // we need to check if any of the commands match the search
    // if they do, we return the commands instead of the main command
    const hasMatchingCommands =
      navigableCommand?.commands?.some((command) =>
        isCommandMatch(command, search)
      ) ?? false;

    if (!hasMatchingCommands) {
      return [];
    }

    return navigableCommand?.commands ?? [];
  }

  return !isSearching || isCommandMatch(item, search) ? [item] : [];
}

import { BlockGroupItem, BlockItem } from '../../../blocks/types';
import { cn } from '../../utils/classname';
import { Editor, Range } from '@tiptap/core';
import { ReactRenderer } from '@tiptap/react';
import { SuggestionOptions } from '@tiptap/suggestion';
import {
  forwardRef,
  Fragment,
  KeyboardEvent,
  RefObject,
  useCallback,
  useEffect,
  useImperativeHandle,
  useLayoutEffect,
  useRef,
  useState,
} from 'react';
import tippy, { GetReferenceClientRect, Instance } from 'tippy.js';
import { DEFAULT_SLASH_COMMANDS } from './default-slash-commands';
import { TooltipProvider } from '../../components/ui/tooltip';
import { SlashCommandItem } from './slash-command-item';
import { filterSlashCommands } from './slash-command-search';

type CommandListProps = {
  items: BlockGroupItem[];
  command: (item: BlockItem) => void;
  editor: Editor;
  range: Range;
  query: string;
};

const CommandList = forwardRef<unknown, CommandListProps>((props, ref) => {
  const { items: groups, command, editor, range, query } = props;

  const [selectedGroupIndex, setSelectedGroupIndex] = useState(0);
  const [selectedCommandIndex, setSelectedCommandIndex] = useState(0);
  const [hoveredItemKey, setHoveredItemKey] = useState<string | null>(null);

  const prevQuery = useRef('');
  const prevSelectedGroupIndex = useRef(0);
  const prevSelectedCommandIndex = useRef(0);

  const selectItem = useCallback(
    (groupIndex: number, commandIndex: number) => {
      const item = groups[groupIndex].commands[commandIndex];
      if (!item) {
        return;
      }

      command(item);
    },
    [command]
  );

  useImperativeHandle(ref, () => ({
    onKeyDown: ({ event }: { event: KeyboardEvent }) => {
      const navigationKeys = [
        'ArrowUp',
        'ArrowDown',
        'Enter',
        'ArrowLeft',
        'ArrowRight',
      ];
      if (navigationKeys.includes(event.key)) {
        let newCommandIndex = selectedCommandIndex;
        let newGroupIndex = selectedGroupIndex;

        switch (event.key) {
          case 'ArrowLeft':
            event.preventDefault();

            const group = groups?.[selectedGroupIndex];
            const isInsideSubCommand = group && 'id' in group;
            if (!isInsideSubCommand) {
              return false;
            }

            editor
              .chain()
              .focus()
              .insertContentAt(range, `/${prevQuery.current}`)
              .run();
            setTimeout(() => {
              setSelectedGroupIndex(prevSelectedGroupIndex.current);
              setSelectedCommandIndex(prevSelectedCommandIndex.current);
            }, 0);
            return true;
          case 'ArrowRight':
            event.preventDefault();

            const command =
              groups?.[selectedGroupIndex]?.commands?.[selectedCommandIndex];
            const isSelectingSubCommand = command && 'commands' in command;
            if (!isSelectingSubCommand) {
              return false;
            }

            selectItem(selectedGroupIndex, selectedCommandIndex);
            prevQuery.current = query;
            prevSelectedGroupIndex.current = selectedGroupIndex;
            prevSelectedCommandIndex.current = selectedCommandIndex;
            return true;
          case 'Enter':
            if (!groups.length) {
              return false;
            }
            selectItem(selectedGroupIndex, selectedCommandIndex);

            prevQuery.current = query;
            prevSelectedGroupIndex.current = selectedGroupIndex;
            prevSelectedCommandIndex.current = selectedCommandIndex;
            return true;
          case 'ArrowUp':
            if (!groups.length) {
              return false;
            }
            newCommandIndex = selectedCommandIndex - 1;
            newGroupIndex = selectedGroupIndex;
            if (newCommandIndex < 0) {
              newGroupIndex = selectedGroupIndex - 1;
              newCommandIndex = groups[newGroupIndex]?.commands.length - 1 || 0;
            }
            if (newGroupIndex < 0) {
              newGroupIndex = groups.length - 1;
              newCommandIndex = groups[newGroupIndex]?.commands.length - 1 || 0;
            }
            setSelectedGroupIndex(newGroupIndex);
            setSelectedCommandIndex(newCommandIndex);
            return true;
          case 'ArrowDown':
            if (!groups.length) {
              return false;
            }
            const commands = groups[selectedGroupIndex].commands;
            newCommandIndex = selectedCommandIndex + 1;
            newGroupIndex = selectedGroupIndex;
            if (commands.length - 1 < newCommandIndex) {
              newCommandIndex = 0;
              newGroupIndex = selectedGroupIndex + 1;
            }
            if (groups.length - 1 < newGroupIndex) {
              newGroupIndex = 0;
            }
            setSelectedGroupIndex(newGroupIndex);
            setSelectedCommandIndex(newCommandIndex);
            return true;
          default:
            return false;
        }
      }
    },
  }));

  const commandListContainer = useRef<HTMLDivElement>(null);
  const activeCommandRef = useRef<HTMLButtonElement | null>(null);

  useLayoutEffect(() => {
    const container = commandListContainer?.current;
    const activeCommandContainer = activeCommandRef?.current;
    if (!container || !activeCommandContainer) {
      return;
    }

    const { offsetTop, offsetHeight } = activeCommandContainer;
    container.style.transition = 'none';
    container.scrollTop = offsetTop - offsetHeight;
  }, [
    selectedGroupIndex,
    selectedCommandIndex,
    commandListContainer,
    activeCommandRef,
  ]);

  useEffect(() => {
    setSelectedGroupIndex(0);
    setSelectedCommandIndex(0);
  }, [groups]);

  useEffect(() => {
    return () => {
      prevQuery.current = '';
      prevSelectedGroupIndex.current = 0;
      prevSelectedCommandIndex.current = 0;
    };
  }, []);

  if (!groups || groups.length === 0) {
    return null;
  }

  return (
    <TooltipProvider>
      <div className="mly:z-50 mly:w-72 mly:overflow-hidden mly:rounded-md mly:border mly:border-gray-200 mly:bg-white mly:shadow-md mly:transition-all">
        <div
          id="slash-command"
          ref={commandListContainer}
          className="mly:no-scrollbar mly:h-auto mly:max-h-[330px] mly:overflow-y-auto"
        >
          {groups.map((group, groupIndex) => (
            <Fragment key={groupIndex}>
              <span
                className={cn(
                  'mly:block mly:border-b mly:border-gray-200 mly:bg-soft-gray mly:p-2 mly:text-xs mly:uppercase mly:text-gray-400',
                  groupIndex > 0 ? 'mly:border-t' : ''
                )}
              >
                {group.title}
              </span>
              <div className="mly:space-y-0.5 mly:p-1">
                {group.commands.map((item, commandIndex) => {
                  const itemKey = `${groupIndex}-${commandIndex}`;
                  return (
                    <SlashCommandItem
                      key={itemKey}
                      item={item}
                      groupIndex={groupIndex}
                      commandIndex={commandIndex}
                      selectedGroupIndex={selectedGroupIndex}
                      selectedCommandIndex={selectedCommandIndex}
                      selectItem={() => selectItem(groupIndex, commandIndex)}
                      editor={editor}
                      activeCommandRef={activeCommandRef}
                      hoveredItemKey={hoveredItemKey}
                      onHover={(isHovered) =>
                        setHoveredItemKey(isHovered ? itemKey : null)
                      }
                    />
                  );
                })}
              </div>
            </Fragment>
          ))}
        </div>
        <div className="mly:border-t mly:border-gray-200 mly:px-1 mly:py-3 mly:pl-4">
          <div className="mly:flex mly:items-center">
            <p className="mly:text-center mly:text-xs mly:text-gray-400">
              <kbd className="mly:rounded mly:border mly:border-gray-200 mly:p-1 mly:px-2 mly:font-medium">
                ↑
              </kbd>
              <kbd className="mly:ml-1 mly:rounded mly:border mly:border-gray-200 mly:p-1 mly:px-2 mly:font-medium">
                ↓
              </kbd>{' '}
              to navigate
            </p>
            <span aria-hidden="true" className="mly:select-none mly:px-1">
              ·
            </span>
            <p className="mly:text-center mly:text-xs mly:text-gray-400">
              <kbd className="mly:rounded mly:border mly:border-gray-200 mly:p-1 mly:px-1.5 mly:font-medium">
                Enter
              </kbd>{' '}
              to select
            </p>
          </div>
        </div>
      </div>
    </TooltipProvider>
  );
});

export function getSlashCommandSuggestions(
  groups: BlockGroupItem[] = DEFAULT_SLASH_COMMANDS
): Omit<SuggestionOptions, 'editor'> {
  return {
    items: ({ query, editor }) => {
      return filterSlashCommands({ query, editor, groups });
    },
    allow: ({ editor }) => {
      const isInsideHTMLCodeBlock = editor.isActive('htmlCodeBlock');
      if (isInsideHTMLCodeBlock) {
        return false;
      }

      return true;
    },
    render: () => {
      let component: ReactRenderer<any>;
      let popup: Instance<any>[] | null = null;

      return {
        onStart: (props) => {
          component = new ReactRenderer(CommandList, {
            props,
            editor: props.editor,
          });

          popup = tippy('body', {
            getReferenceClientRect: props.clientRect as GetReferenceClientRect,
            appendTo: () => document.body,
            content: component.element,
            showOnCreate: true,
            interactive: true,
            trigger: 'manual',
            placement: 'top-start',
          });
        },
        onUpdate: (props) => {
          const currentPopup = popup?.[0];
          if (!currentPopup || currentPopup?.state?.isDestroyed) {
            return;
          }

          component?.updateProps(props);
          currentPopup.setProps({
            getReferenceClientRect: props.clientRect,
          });
        },
        onKeyDown: (props) => {
          if (props.event.key === 'Escape') {
            const currentPopup = popup?.[0];
            if (!currentPopup?.state?.isDestroyed) {
              currentPopup?.destroy();
            }

            component?.destroy();
            return true;
          }

          return component?.ref?.onKeyDown(props);
        },
        onExit: () => {
          if (!popup || !popup?.[0] || !component) {
            return;
          }

          const currentPopup = popup?.[0];
          if (!currentPopup.state.isDestroyed) {
            currentPopup.destroy();
          }

          component?.destroy();
        },
      };
    },
  };
}

