  allowedButtonVariant,
  ButtonAttributes,
} from './button';
import { ButtonLabelInput } from './button-label-input';

export function ButtonView(props: NodeViewProps) {
  const { node, editor, getPos, updateAttributes } = props;
  const {
    text,
    isTextVariable,
    alignment,
    variant,
    borderRadius: _radius,
    buttonColor,
    textColor,
    url: externalLink,
    showIfKey = '',
    isUrlVariable,
    paddingTop,
    paddingRight,
    paddingBottom,
    paddingLeft,
  } = node.attrs as ButtonAttributes;

  const opts = useVariableOptions(editor);
  const renderVariable = opts?.renderVariable;

  const sizes = useMemo(
    () => ({
      small: {
        paddingX: 24,
        paddingY: 6,
      },
      medium: {
        paddingX: 32,
        paddingY: 10,
      },
      large: {
        paddingX: 40,
        paddingY: 14,
      },
    }),
    []
  );

  const size = useMemo(() => {
    return Object.entries(sizes).find(
      ([, { paddingX, paddingY }]) =>
        paddingRight === paddingX && paddingTop === paddingY
    )?.[0] as 'small' | 'medium' | 'large';
  }, [paddingRight, paddingTop, sizes]);

  return (
    <NodeViewWrapper
      draggable={editor.isEditable}
      data-drag-handle={editor.isEditable}
      data-type="button"
      style={{
        textAlign: alignment,
      }}
    >
      <Popover open={props.selected && editor.isEditable}>
        <PopoverTrigger asChild>
          <div>
            <button
              className={cn(
                'mly:inline-flex mly:items-center mly:justify-center mly:rounded-md mly:text-sm mly:font-medium mly:ring-offset-white mly:transition-colors mly:disabled:pointer-events-none mly:disabled:opacity-50',
                'mly:font-semibold mly:no-underline',
                {
                  'mly:rounded-full!': _radius === 'round',
                  'mly:rounded-md!': _radius === 'smooth',
                  'mly:rounded-none!': _radius === 'sharp',
                }
              )}
              tabIndex={-1}
              style={
                {
                  backgroundColor:
                    variant === 'filled'
                      ? buttonColor || 'var(--mly-button-background-color)'
                      : 'transparent',
                  color: textColor || 'var(--mly-button-text-color)',

                  borderWidth: 2,
                  borderStyle: 'solid',
                  borderColor:
                    buttonColor || 'var(--mly-button-background-color)',
                  // decrease the border color opacity to 80%
                  // so that it's not too prominent
                  '--button-var-border-color': textColor
                    ? `${textColor}80`
                    : 'color-mix(in srgb, var(--mly-button-text-color) 80%, transparent)',

                  paddingTop: paddingTop || 'var(--mly-button-padding-top)',
                  paddingRight:
                    paddingRight || 'var(--mly-button-padding-right)',
                  paddingBottom:
                    paddingBottom || 'var(--mly-button-padding-bottom)',
                  paddingLeft: paddingLeft || 'var(--mly-button-padding-left)',
                } as CSSProperties
              }
              onClick={(e) => {
                e.preventDefault();
                if (!editor.isEditable) {
                  return;
                }

                const pos = getPos();
                editor.commands.setNodeSelection(pos);
              }}
            >
              {isTextVariable
                ? renderVariable({
                    variable: { name: text, valid: true },
                    fallback: text,
                    from: 'button-variable',
                    editor,
                  })
                : text}
            </button>
          </div>
        </PopoverTrigger>
        <PopoverContent
          align="end"
          side="top"
          className="mly:w-max mly:rounded-lg mly:p-0.5!"
          sideOffset={8}
          onOpenAutoFocus={(e) => e.preventDefault()}
          onCloseAutoFocus={(e) => e.preventDefault()}
        >
          <TooltipProvider>
            <div className="mly:flex mly:items-stretch mly:text-midnight-gray">
              <ButtonLabelInput
                value={text}
                onValueChange={(value, isVariable) => {
                  updateAttributes({
                    text: value,
                    isTextVariable: isVariable ?? false,
                  });
                }}
                isVariable={isTextVariable}
                editor={editor}
              />

              <Divider />

              <div className="mly:flex mly:gap-x-0.5">
                <Select
                  label="Border Radius"
                  value={_radius}
                  options={allowedButtonBorderRadius.map((value) => ({
                    value,
                    label: value,
                  }))}
                  onValueChange={(value) => {
                    updateAttributes({
                      borderRadius: value,
                    });
                  }}
                  tooltip="Border Radius"
                  className="mly:capitalize"
                />

                <Select
                  label="Style"
                  value={variant}
                  options={allowedButtonVariant.map((value) => ({
                    value,
                    label: value,
                  }))}
                  onValueChange={(value) => {
                    updateAttributes({
                      variant: value,
                    });
                  }}
                  tooltip="Style"
                  className="mly:capitalize"
                />

                <Select
                  label="Size"
                  value={size}
                  options={[
                    { value: 'small', label: 'Small' },
                    { value: 'medium', label: 'Medium' },
                    { value: 'large', label: 'Large' },
                  ]}
                  onValueChange={(value) => {
                    const { paddingX, paddingY } =
                      sizes[value as 'small' | 'medium' | 'large'];

                    updateAttributes({
                      paddingTop: paddingY,
                      paddingRight: paddingX,
                      paddingBottom: paddingY,
                      paddingLeft: paddingX,
                    });
                  }}
                  tooltip="Size"
                  placeholder="Size"
                />
              </div>

              <Divider />

              <div className="mly:flex mly:gap-x-0.5">
                <AlignmentSwitch
                  alignment={alignment}
                  onAlignmentChange={(alignment) => {
                    updateAttributes({
                      alignment,
                    });
                  }}
                />

                <LinkInputPopover
                  defaultValue={externalLink || ''}
                  onValueChange={(value, isVariable) => {
                    updateAttributes({
                      url: value,
                      isUrlVariable: isVariable ?? false,
                    });
                  }}
                  tooltip="Update External Link"
                  editor={editor}
                  isVariable={isUrlVariable}
                />
              </div>

              <Divider />

              <div className="mly:flex mly:gap-x-0.5">
                <BackgroundColorPickerPopup
                  variant={variant}
                  color={buttonColor || 'transparent'}
                  onChange={(color) => {
                    updateAttributes({
                      buttonColor: color,
                    });
                  }}
                />

                <TextColorPickerPopup
                  color={textColor || 'transparent'}
                  onChange={(color) => {
                    updateAttributes({
                      textColor: color,
                    });
                  }}
                />
              </div>

              <Divider />

              <ShowPopover
                showIfKey={showIfKey}
                onShowIfKeyValueChange={(value) => {
                  updateAttributes({
                    showIfKey: value,
                  });
                }}
                editor={editor}
              />
            </div>
          </TooltipProvider>
        </PopoverContent>
      </Popover>
    </NodeViewWrapper>
  );
}

type ColorPickerProps = {
  variant?: AllowedButtonVariant;
  color: string;
  onChange: (color: string) => void;
};

function BackgroundColorPickerPopup(props: ColorPickerProps) {
  const { color, onChange, variant } = props;

  return (
    <ColorPicker
      color={color}
      onColorChange={onChange}
      tooltip="Background Color"
    >
      <BaseButton
        variant="ghost"
        size="sm"
        type="button"
        className="mly:size-7"
      >
        <div
          className="mly:h-4 mly:w-4 mly:shrink-0 mly:rounded-full mly:shadow"
          style={{
            backgroundColor: variant === 'filled' ? color : 'transparent',
            borderStyle: 'solid',
            borderWidth: 2,
            borderColor: variant === 'filled' ? 'white' : color,
          }}
        />
      </BaseButton>
    </ColorPicker>
  );
}

function TextColorPickerPopup(props: ColorPickerProps) {
  const { color, onChange } = props;

  return (
    <ColorPicker color={color} onColorChange={onChange} tooltip="Text Color">
      <BaseButton
        variant="ghost"
        size="sm"
        type="button"
        className="mly:size-7"
      >
        <div className="mly:flex mly:flex-col mly:items-center mly:justify-center mly:gap-px">
          <span className="mly:font-bolder mly:font-mono mly:text-xs mly:text-midnight-gray">
            A
          </span>
          <div
            className="mly:h-[2px] mly:w-3 mly:shrink-0 mly:rounded-md mly:shadow"
            style={{ backgroundColor: color }}
          />
        </div>
      </BaseButton>
    </ColorPicker>
  );
}

