import { mergeAttributes, Node } from '@tiptap/core';

export const DEFAULT_SECTION_BACKGROUND_COLOR = '#f7f7f7';
export const DEFAULT_SECTION_ALIGN = 'left';
export const DEFAULT_SECTION_BORDER_WIDTH = 2;
export const DEFAULT_SECTION_BORDER_COLOR = '#e2e2e2';
export const DEFAULT_SECTION_BORDER_RADIUS = 0;

export const DEFAULT_SECTION_MARGIN_TOP = 0;
export const DEFAULT_SECTION_MARGIN_RIGHT = 0;
export const DEFAULT_SECTION_MARGIN_BOTTOM = 0;
export const DEFAULT_SECTION_MARGIN_LEFT = 0;

export const DEFAULT_SECTION_PADDING_TOP = 0;
export const DEFAULT_SECTION_PADDING_RIGHT = 0;
export const DEFAULT_SECTION_PADDING_BOTTOM = 0;
export const DEFAULT_SECTION_PADDING_LEFT = 0;

export const DEFAULT_SECTION_SHOW_IF_KEY = null;

type SectionAttributes = {
  borderRadius: number;
  backgroundColor: string;
  align: string;
  borderWidth: number;
  borderColor: string;

  marginTop: number;
  marginRight: number;
  marginBottom: number;
  marginLeft: number;

  paddingTop: number;
  paddingRight: number;
  paddingBottom: number;
  paddingLeft: number;

  showIfKey: string | null;
};

declare module '@tiptap/core' {
  interface Commands<ReturnType> {
    section: {
      setSection: () => ReturnType;
      updateSection: (attrs: Partial<SectionAttributes>) => ReturnType;
    };
  }
}

export const SectionExtension = Node.create({
  name: 'section',
  group: 'block',
  content: '(block|columns)+',
  defining: true,
  isolating: true,

  addAttributes() {
    return {
      borderRadius: {
        default: 0,
        parseHTML: (element) => {
          return Number(element?.style?.borderRadius?.replace(/['"]+/g, ''));
        },
        renderHTML: (attributes) => {
          if (!attributes.borderRadius) {
            return {};
          }

          return {
            style: `border-radius: ${attributes.borderRadius}px`,
          };
        },
      },
      backgroundColor: {
        default: DEFAULT_SECTION_BACKGROUND_COLOR,
        parseHTML: (element) => {
          return element.style.backgroundColor;
        },
        renderHTML: (attributes) => {
          if (!attributes.backgroundColor) {
            return {};
          }

          return {
            style: `background-color: ${attributes.backgroundColor};--bg-color: ${attributes.backgroundColor}`,
          };
        },
      },
      align: {
        default: DEFAULT_SECTION_ALIGN,
        parseHTML: (element) => {
          return element.getAttribute('align') || DEFAULT_SECTION_ALIGN;
        },
        renderHTML(attributes) {
          if (!attributes.align) {
            return {};
          }

          return {
            align: attributes.align,
          };
        },
      },
      borderWidth: {
        default: DEFAULT_SECTION_BORDER_WIDTH,
        parseHTML: (element) => {
          return (
            Number(element?.style?.borderWidth?.replace(/['"]+/g, '')) || 0
          );
        },
        renderHTML: (attributes) => {
          if (!attributes.borderWidth) {
            return {};
          }

          return {
            style: `border-width: ${attributes.borderWidth}px`,
          };
        },
      },
      borderColor: {
        default: DEFAULT_SECTION_BORDER_COLOR,
        parseHTML: (element) => {
          return element.style.borderColor;
        },
        renderHTML: (attributes) => {
          if (!attributes.borderColor) {
            return {};
          }

          return {
            style: `border-color: ${attributes.borderColor}`,
          };
        },
      },
      paddingTop: {
        default: DEFAULT_SECTION_PADDING_TOP,
        parseHTML: (element) => {
          return Number(element?.style?.paddingTop?.replace(/['"]+/g, '')) || 0;
        },
        renderHTML: (attributes) => {
          if (!attributes.paddingTop) {
            return {};
          }

          return {
            style: `padding-top: ${attributes.paddingTop}px`,
          };
        },
      },
      paddingRight: {
        default: DEFAULT_SECTION_PADDING_RIGHT,
        parseHTML: (element) =>
          Number(element?.style?.paddingRight?.replace(/['"]+/g, '')) || 0,
        renderHTML: (attributes) => {
          if (!attributes.paddingRight) {
            return {};
          }

          return {
            style: `padding-right: ${attributes.paddingRight}px`,
          };
        },
      },
      paddingBottom: {
        default: DEFAULT_SECTION_PADDING_BOTTOM,
        parseHTML: (element) =>
          Number(element?.style?.paddingBottom?.replace(/['"]+/g, '')) || 0,
        renderHTML: (attributes) => {
          if (!attributes.paddingBottom) {
            return {};
          }

          return {
            style: `padding-bottom: ${attributes.paddingBottom}px`,
          };
        },
      },
      paddingLeft: {
        default: DEFAULT_SECTION_PADDING_LEFT,
        parseHTML: (element) =>
          Number(element?.style?.paddingLeft?.replace(/['"]+/g, '')) || 0,
        renderHTML: (attributes) => {
          if (!attributes.paddingLeft) {
            return {};
          }

          return {
            style: `padding-left: ${attributes.paddingLeft}px`,
          };
        },
      },
      marginTop: {
        default: DEFAULT_SECTION_MARGIN_TOP,
        parseHTML: (element) => {
          return Number(element?.style?.marginTop?.replace(/['"]+/g, '')) || 0;
        },
        renderHTML: (attributes) => {
          if (!attributes.marginTop) {
            return {};
          }

          return {
            marginTop: attributes.marginTop,
          };
        },
      },
      marginRight: {
        default: DEFAULT_SECTION_MARGIN_RIGHT,
        parseHTML: (element) =>
          Number(element?.style?.marginRight?.replace(/['"]+/g, '')) || 0,
        renderHTML: (attributes) => {
          if (!attributes.marginRight) {
            return {};
          }

          return {
            marginRight: attributes.marginRight,
          };
        },
      },
      marginBottom: {
        default: DEFAULT_SECTION_MARGIN_BOTTOM,
        parseHTML: (element) =>
          Number(element?.style?.marginBottom?.replace(/['"]+/g, '')) || 0,
        renderHTML: (attributes) => {
          if (!attributes.marginBottom) {
            return {};
          }

          return {
            marginBottom: attributes.marginBottom,
          };
        },
      },
      marginLeft: {
        default: DEFAULT_SECTION_MARGIN_LEFT,
        parseHTML: (element) =>
          Number(element?.style?.marginLeft?.replace(/['"]+/g, '')) || 0,
        renderHTML: (attributes) => {
          if (!attributes.marginLeft) {
            return {};
          }

          return {
            marginLeft: attributes.marginLeft,
          };
        },
      },

      showIfKey: {
        default: DEFAULT_SECTION_SHOW_IF_KEY,
        parseHTML: (element) => {
          return (
            element.getAttribute('data-show-if-key') ||
            DEFAULT_SECTION_SHOW_IF_KEY
          );
        },
        renderHTML(attributes) {
          if (!attributes.showIfKey) {
            return {};
          }

          return {
            'data-show-if-key': attributes.showIfKey,
          };
        },
      },
    };
  },

  addCommands() {
    return {
      setSection:
        () =>
        ({ commands }) => {
          return commands.insertContent({
            type: this.name,
            attrs: {
              type: this.name,
            },
            content: [
              {
                type: 'paragraph',
              },
            ],
          });
        },
      updateSection: (attrs) => updateAttributes(this.name, attrs),
    };
  },

  renderHTML({ HTMLAttributes }) {
    const {
      marginTop = 0,
      marginRight = 0,
      marginBottom = 0,
      marginLeft = 0,
    } = HTMLAttributes;

    return [
      'table',
      {
        'data-type': this.name,
        border: 0,
        cellpadding: 0,
        cellspacing: 0,
        class: 'mly:w-full mly:border-separate mly:relative mly:table-fixed',
        style: `margin-top: ${marginTop}px; margin-right: ${marginRight}px; margin-bottom: ${marginBottom}px; margin-left: ${marginLeft}px;`,
      },
      [
        'tbody',
        {
          class: 'mly:w-full',
        },
        [
          'tr',
          {
            class: 'mly:w-full',
          },
          [
            'td',
            mergeAttributes(HTMLAttributes, {
              'data-type': 'section-cell',
              style: 'border-style: solid',
              class: 'mly:w-full mly:[text-align:revert-layer]',
            }),
            0,
          ],
        ],
      ],
    ];
  },

  parseHTML() {
    return [
      {
        tag: 'table[data-type="section"]',
      },
    ];
  },
});

import { mergeAttributes, Node } from '@tiptap/core';
import { DEFAULT_SECTION_SHOW_IF_KEY } from './section/section';

export interface SpacerOptions {
  height: number;
  showIfKey: string;
  HTMLAttributes: Record<string, any>;
}

declare module '@tiptap/core' {
  interface Commands<ReturnType> {
    spacer: {
      setSpacer: (options: { height: number }) => ReturnType;
      setSpacerSize: (height: number) => ReturnType;
      setSpacerShowIfKey: (showIfKey: string) => ReturnType;
      unsetSpacer: () => ReturnType;
    };
  }
}

export const DEFAULT_SPACER_HEIGHT = 8;

export const Spacer = Node.create<SpacerOptions>({
  name: 'spacer',
  priority: 1000,

  group: 'block',
  draggable: true,
  addAttributes() {
    return {
      height: {
        default: DEFAULT_SPACER_HEIGHT,
        parseHTML: (element) => Number(element.getAttribute('data-height')),
        renderHTML: (attributes) => {
          return {
            'data-height': attributes.height,
          };
        },
      },
      showIfKey: {
        default: DEFAULT_SECTION_SHOW_IF_KEY,
        parseHTML: (element) => {
          return (
            element.getAttribute('data-show-if-key') ||
            DEFAULT_SECTION_SHOW_IF_KEY
          );
        },
        renderHTML(attributes) {
          if (!attributes.showIfKey) {
            return {};
          }

          return {
            'data-show-if-key': attributes.showIfKey,
          };
        },
      },
    };
  },

  addCommands() {
    return {
      setSpacer:
        (options) =>
        ({ commands }) => {
          return commands.insertContent({
            type: this.name,
            attrs: {
              height: options.height,
            },
          });
        },

      setSpacerSize:
        (height) =>
        ({ commands }) => {
          return commands.updateAttributes('spacer', { height });
        },

      setSpacerShowIfKey:
        (showIfKey) =>
        ({ commands }) => {
          return commands.updateAttributes('spacer', { showIfKey });
        },

      unsetSpacer:
        () =>
        ({ commands }) => {
          return commands.deleteNode('spacer');
        },
    };
  },
  renderHTML({ HTMLAttributes, node }) {
    const { height } = node.attrs as SpacerOptions;

    return [
      'div',
      mergeAttributes(
        {
          'data-maily-component': this.name,
        },
        this.options.HTMLAttributes,
        HTMLAttributes,
        {
          class: 'spacer mly:relative mly:full mly:z-50',
          contenteditable: false,
          style: `height: ${height}px;--spacer-height: ${height}px;`,
        }
      ),
    ];
  },
  parseHTML() {
    return [{ tag: `div[data-maily-component="${this.name}"]` }];
  },
});

import { IconPlaceholder } from "@/components/icon-placeholder"
import { cn } from '../../utils/classname';

import {
  forwardRef,
  useEffect,
  useImperativeHandle,
  useRef,
  useState,
} from 'react';
import { Variable } from './variable';

export type VariableSuggestionsPopoverProps = {
  items: Variable[];
  onSelectItem: (item: Variable) => void;
};

export type VariableSuggestionsPopoverRef = {
  moveUp: () => void;
  moveDown: () => void;
  select: () => void;
};

export type VariableSuggestionsPopoverType = React.ForwardRefExoticComponent<
  VariableSuggestionsPopoverProps &
    React.RefAttributes<VariableSuggestionsPopoverRef>
>;

export const VariableSuggestionsPopover: VariableSuggestionsPopoverType =
  forwardRef((props, ref) => {
    const { items, onSelectItem } = props;

    const [selectedIndex, setSelectedIndex] = useState(0);
    const scrollContainerRef = useRef<HTMLDivElement>(null);
    const itemRefs = useRef<(HTMLButtonElement | null)[]>([]);

    const scrollSelectedIntoView = (index: number) => {
      const container = scrollContainerRef.current;
      const selectedItem = itemRefs.current[index];

      if (!container || !selectedItem) {
        return;
      }

      const containerRect = container.getBoundingClientRect();
      const itemRect = selectedItem.getBoundingClientRect();

      const padding = 4;
      if (itemRect.bottom > containerRect.bottom) {
        container.scrollTop += itemRect.bottom - containerRect.bottom + padding;
      } else if (itemRect.top < containerRect.top) {
        container.scrollTop += itemRect.top - containerRect.top - padding;
      }
    };

    useEffect(() => {
      setSelectedIndex(0);
      if (scrollContainerRef.current) {
        scrollContainerRef.current.scrollTop = 0;
      }
      itemRefs.current = items.map(() => null);
    }, [items]);

    useEffect(() => {
      scrollSelectedIntoView(selectedIndex);
    }, [selectedIndex]);

    useImperativeHandle(ref, () => ({
      moveUp: () => {
        setSelectedIndex((selectedIndex + items.length - 1) % items.length);
      },
      moveDown: () => {
        setSelectedIndex((selectedIndex + 1) % items.length);
      },
      select: () => {
        const item = items[selectedIndex];
        if (!item) {
          return;
        }

        onSelectItem(item);
      },
    }));

    return (
      <div className="mly:z-50 mly:w-64 mly:rounded-lg mly:border mly:border-gray-200 mly:bg-white mly:shadow-md mly:transition-all">
        <div className="mly:flex mly:items-center mly:justify-between mly:gap-2 mly:border-b mly:border-gray-200 mly:bg-soft-gray/40 mly:px-1 mly:py-1.5 mly:text-gray-500">
          <span className="mly:text-xs mly:uppercase">Variables</span>
          <VariableIcon>
            <IconPlaceholder
  lucide="Braces"
  tabler="IconBraces"
  hugeicons="BracesIcon"
  phosphor="BracketsCurly"
  remixicon="RiBracesLine"
  className="mly:size-3 mly:stroke-[2.5]"
/>
          </VariableIcon>
        </div>

        <div
          ref={scrollContainerRef}
          className="mly:max-h-52 mly:overflow-y-auto mly:scrollbar-thin mly:scrollbar-track-transparent mly:scrollbar-thumb-gray-200"
        >
          <div className="mly:flex mly:w-fit mly:min-w-full mly:flex-col mly:gap-0.5 mly:p-1">
            {items?.length ? (
              items?.map((item, index: number) => (
                <button
                  key={index}
                  ref={(el) => (itemRefs.current[index] = el)}
                  onClick={() => onSelectItem(item)}
                  className={cn(
                    'mly:flex mly:w-fit mly:min-w-full mly:items-center mly:gap-2 mly:rounded-md mly:px-2 mly:py-1 mly:text-left mly:font-mono mly:text-sm mly:text-gray-900 mly:hover:bg-soft-gray',
                    index === selectedIndex
                      ? 'mly:bg-soft-gray'
                      : 'mly:bg-white'
                  )}
                >
                  <IconPlaceholder
  lucide="Braces"
  tabler="IconBraces"
  hugeicons="BracesIcon"
  phosphor="BracketsCurly"
  remixicon="RiBracesLine"
  className="mly:size-3 mly:stroke-[2.5] mly:text-rose-600"
/>
                  {item?.label || item.name}
                </button>
              ))
            ) : (
              <div className="mly:flex mly:h-7 mly:w-full mly:items-center mly:gap-2 mly:rounded-md mly:px-2 mly:py-1 mly:text-left mly:font-mono mly:text-[13px] mly:text-gray-900 mly:hover:bg-soft-gray">
                No result
              </div>
            )}
          </div>
        </div>

        <div className="mly:flex mly:items-center mly:justify-between mly:gap-2 mly:border-t mly:border-gray-200 mly:px-1 mly:py-1.5 mly:text-gray-500">
          <div className="mly:flex mly:items-center mly:gap-1">
            <VariableIcon>
              <IconPlaceholder
  lucide="ArrowDownIcon"
  tabler="IconArrowDown"
  hugeicons="ArrowDown01Icon"
  phosphor="ArrowDown"
  remixicon="RiArrowDownLine"
  className="mly:size-3 mly:stroke-[2.5]"
/>
            </VariableIcon>
            <VariableIcon>
              <IconPlaceholder
  lucide="ArrowUpIcon"
  tabler="IconArrowUp"
  hugeicons="ArrowUp01Icon"
  phosphor="ArrowUp"
  remixicon="RiArrowUpLine"
  className="mly:size-3 mly:stroke-[2.5]"
/>
            </VariableIcon>
            <span className="mly:text-xs mly:text-gray-500">Navigate</span>
          </div>
          <VariableIcon>
            <IconPlaceholder
  lucide="CornerDownLeftIcon"
  tabler="IconCornerDownLeft"
  hugeicons="CornerDownLeftIcon"
  phosphor="ArrowBendDownLeft"
  remixicon="RiCornerDownLeftLine"
  className="mly:size-3 mly:stroke-[2.5]"
/>
          </VariableIcon>
        </div>
      </div>
    );
  });

