import { Command } from '@tiptap/core';

export function updateAttribute(
  type: string,
  attr: string,
  value: any
): Command {
  return ({ commands }) =>
    commands.command(({ tr, state, dispatch }) => {
      if (dispatch) {
        let lastPos = null;

        tr.selection.ranges.forEach((range) => {
          state.doc.nodesBetween(
            range.$from.pos,
            range.$to.pos,
            (node, pos) => {
              if (node.type.name === type) {
                lastPos = pos;
              }
            }
          );
        });

        if (lastPos !== null) {
          tr.setNodeAttribute(lastPos, attr, value);
        }
      }

      return true;
    });
}

export function updateAttributes(
  type: string,
  attrs: Record<string, any>
): Command {
  return ({ commands }) =>
    commands.command(({ tr, state, dispatch }) => {
      if (dispatch) {
        let lastPos = null;

        tr.selection.ranges.forEach((range) => {
          state.doc.nodesBetween(
            range.$from.pos,
            range.$to.pos,
            (node, pos) => {
              if (node.type.name === type) {
                lastPos = pos;
              }
            }
          );
        });

        if (lastPos !== null) {
          const node = state.doc.nodeAt(lastPos);
          if (node) {
            tr.setNodeMarkup(lastPos, null, {
              ...node.attrs,
              ...attrs,
            });
          } else {
            for (const [key, value] of Object.entries(attrs)) {
              tr.setNodeAttribute(lastPos, key, value);
            }
          }
        }

        if (type === 'button') {
          tr.setSelection(tr.selection);
        }
      }

      return true;
    });
}

export const updateScrollView = (container: HTMLElement, item: HTMLElement) => {
  const containerHeight = container.offsetHeight;
  const itemHeight = item ? item.offsetHeight : 0;

  const top = item.offsetTop;
  const bottom = top + itemHeight;

  if (top < container.scrollTop) {
    container.scrollTop -= container.scrollTop - top + 5;
  } else if (bottom > containerHeight + container.scrollTop) {
    container.scrollTop += bottom - containerHeight - container.scrollTop + 5;
  }
};

import { useCallback, useLayoutEffect, useRef } from 'react';

export const useEvent = <T extends (...args: any[]) => any>(handler: T): T => {
  const handlerRef = useRef<T | null>(null);

  useLayoutEffect(() => {
    handlerRef.current = handler;
  }, [handler]);

  return useCallback((...args: Parameters<T>): ReturnType<T> => {
    if (handlerRef.current === null) {
      throw new Error('Handler is not assigned');
    }
    return handlerRef.current(...args);
  }, []) as T;
};

import { useCallback } from 'react';
import { useEffect } from 'react';
import { RefObject } from 'react';

export function useOutsideClick(
  ref: RefObject<HTMLElement>,
  callback: () => void
) {
  const handleClick = useCallback(
    (e: MouseEvent | TouchEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        callback();
      }
    },
    [ref, callback]
  );

  useEffect(() => {
    document.addEventListener('mousedown', handleClick);
    document.addEventListener('touchstart', handleClick);
    return () => {
      document.removeEventListener('mousedown', handleClick);
      document.removeEventListener('touchstart', handleClick);
    };
  }, [handleClick]);
}

import type {
  VariableFunctionOptions,
  Variables,
  Variable,
} from '../../extensions';

export function processVariables(
  variables: Variables,
  options: VariableFunctionOptions
): Array<Variable> {
  const { query } = options;
  const queryLower = query.toLowerCase();

  let filteredVariables: Array<Variable> = [];
  if (Array.isArray(variables)) {
    filteredVariables = variables.filter((variable) =>
      variable.name.toLowerCase().startsWith(queryLower)
    );

    if (
      query.length > 0 &&
      !filteredVariables.some((variable) => variable.name === query)
    ) {
      filteredVariables.push({ name: query, required: true });
    }

    return filteredVariables;
  } else if (typeof variables === 'function') {
    return variables(options);
  } else {
    throw new Error(`Invalid variables type. Expected 'Array' or 'Function', but received '${typeof variables}'.

You can check out the documentation for more information: https://github.com/arikchakma/maily.to/blob/main/packages/core/readme.md`);
  }
}

